from collections import deque

def bfs(graph, start):
    dist = {start: 0}
    q = deque([start])
    while q:
        v = q.popleft()
        for nv in graph[v]:
            if nv in dist:
                continue
            dist[nv] = dist[v] + 1
            q.append(nv)
    return dist

