use std::cmp::Reverse;
use std::collections::BinaryHeap;

fn dijkstra(start: usize, graph: &[Vec<(usize, i64)>]) -> Vec<i64> {
    let inf = i64::MAX / 4;
    let mut dist = vec![inf; graph.len()];
    let mut pq = BinaryHeap::new();
    dist[start] = 0;
    pq.push((Reverse(0_i64), start));

    while let Some((Reverse(d), v)) = pq.pop() {
        if d != dist[v] {
            continue;
        }
        for &(nv, w) in &graph[v] {
            if dist[nv] > d + w {
                dist[nv] = d + w;
                pq.push((Reverse(dist[nv]), nv));
            }
        }
    }

    dist
}
